        this->logInfo("Starting processing...");

        // Process data
        for (int val : data) {
            // ...
        }

        this->logInfo("Processing complete");
    }

    std::string name() const { return "DataProcessor"; }

    void showStats() const {
        this->printMetrics();
    }
};

