class SafePool {
    T* storage;
    std::vector<T*> freeList;
    bool used[N] = {};  // Track allocation state

public:
    T* allocate() {
        if (freeList.empty()) throw std::bad_alloc();

        T* obj = freeList.back();
        freeList.pop_back();

        size_t index = obj - storage;
        used[index] = true;  // Mark as allocated
        return obj;
    }

