        if (index >= N) {
            throw std::invalid_argument("Pointer not from pool");
        }

        if (!used[index]) {
            throw std::logic_error("Double-free detected!");  // Catch error
        }

        used[index] = false;  // Mark as free
        freeList.push_back(ptr);
    }
