template <typename T>
class PoolPtr {
    T* ptr;
    ObjectPool<T>* pool;

public:
    PoolPtr(T* p, ObjectPool<T>* pl) : ptr(p), pool(pl) {}

    ~PoolPtr() {
        if (ptr && pool) {
            pool->deallocate(ptr);  // ✅ Automatic return
        }
    }

    // Move semantics
    PoolPtr(PoolPtr&& other) noexcept
        : ptr(other.ptr), pool(other.pool) {
        other.ptr = nullptr;
    }

    // Disable copy
