for (int i = 0; i < 10; ++i) {
    threads.emplace_back([&] {
        for (int j = 0; j < 1000; ++j) {
            T* obj = pool.allocate();
            pool.deallocate(obj);
        }
    });
}

// 4. Leak test
{
    Pool pool;
    pool.allocate();
    // Don't deallocate
}  // Pool destructor should detect leak
