        alloc.deallocate(data, capacity);
        data = new_data;
        capacity = new_cap;
    }

    ~Vector() {
        for (std::size_t i = 0; i < size; ++i) {
            alloc.destroy(&data[i]);
        }
        alloc.deallocate(data, capacity);
    }
